        }, 
        {
            "bucket_id": "2f9b1aaa-552d-48e8-1b78-371dd08688b3", 
            "permissions": [
                "write", 
                "read", 
                "collection:create", 
                "group:create"
            ], 
            "resource_name": "bucket", 
            "uri": "/buckets/2f9b1aaa-552d-48e8-1b78-371dd08688b3"
        }
    ]
}

```

